#!/usr/bin/env dotnet
// Find earliest Friday the 13th in proleptic Gregorian calendar (from 0001-01-01)
// and count total Friday the 13ths in a full 400-year cycle.

// --- Find the earliest Friday the 13th ---
DateOnly earliest = default;
for (int year = 1; year <= 1; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            earliest = d;
            break;
        }
    }
    if (earliest != default) break;
}

// Brute-force search in case year 1 has none
if (earliest == default)
{
    for (int year = 2; year <= 400; year++)
    {
        for (int month = 1; month <= 12; month++)
        {
            var d = new DateOnly(year, month, 13);
            if (d.DayOfWeek == DayOfWeek.Friday)
            {
                earliest = d;
                break;
            }
        }
        if (earliest != default) break;
    }
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");

// --- Count Friday the 13ths in a full 400-year cycle (years 1–400) ---
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");

// --- Bonus: distribution by month ---
Console.WriteLine("\nDistribution by month:");
var byMonth = new int[13];
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
            byMonth[month]++;
    }
}
for (int m = 1; m <= 12; m++)
    Console.WriteLine($"  {new DateOnly(2000, m, 1):MMMM,-12} {byMonth[m]}");
EOF
